import React, { useState } from "react";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import Toast from "../components/Toast";
import { toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

function AdminLogin({ setAuth }) {
  const [phoneNumber, setPhoneNumber] = useState("");
  const [otp, setOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const API_BASE_URL = "http://localhost:5000/api";

  // ---------- SEND OTP ----------
  const handleSendOtp = async (e) => {
    e.preventDefault();
    if (!/^\d{10}$/.test(phoneNumber)) {
      toast.error("Phone number must be 10 digits");
      return;
    }
    setLoading(true);
    try {
      const startTime = Date.now();
      const response = await axios.post(`${API_BASE_URL}/admin/send-otp`, { phone: phoneNumber });
      const elapsedTime = Date.now() - startTime;
      const remainingTime = Math.max(0, 500 - elapsedTime);
      await new Promise((resolve) => setTimeout(resolve, remainingTime));

      if (response.data.status) {
        setOtpSent(true);
        toast.success("OTP sent successfully!");
      } else {
        toast.error(response.data.error || "Failed to send OTP");
      }
    } catch (err) {
      if (err.response) {
        toast.error(err.response.data.error || `Error: ${err.response.status}`);
      } else if (err.request) {
        toast.error("No response from server. Check API URL or server status.");
      } else {
        toast.error("Error sending OTP: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // ---------- VERIFY OTP ----------
  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    if (!/^\d{6}$/.test(otp)) {
      toast.error("OTP must be 6 digits");
      return;
    }
    setLoading(true);
    try {
      const startTime = Date.now();
      const response = await axios.post(`${API_BASE_URL}/admin/verify-otp`, { phone: phoneNumber, otp });
      const elapsedTime = Date.now() - startTime;
      const remainingTime = Math.max(0, 500 - elapsedTime);
      await new Promise((resolve) => setTimeout(resolve, remainingTime));

      if (response.data.status) {
        Cookies.set("adminToken", response.data.token, { expires: 7 });
        Cookies.set("adminPhoneNumber", response.data.encryptedPhone, { expires: 7 });
        toast.success("Logged in Successfully!");
        if (setAuth) setAuth(true);
        setTimeout(() => navigate("/dashboard"), 500);
      } else {
        toast.error(response.data.error || "Invalid OTP");
      }
    } catch (err) {
      if (err.response) {
        toast.error(err.response.data.error || `Error: ${err.response.status}`);
      } else if (err.request) {
        toast.error("No response from server. Check API URL or server status.");
      } else {
        toast.error("Error verifying OTP: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  // ---------- Inline Styles ----------
  const styles = {
    container: {
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      minHeight: "100vh",
      background: "linear-gradient(135deg, #6B73FF 0%, #000DFF 100%)",
      padding: "20px",
    },
    card: {
      maxWidth: "400px",
      width: "100%",
      borderRadius: "15px",
      padding: "30px",
      boxShadow: "0 10px 25px rgba(0,0,0,0.2)",
      backgroundColor: "#ffffff",
    },
    logo: {
      width: "180px",
      height: "auto",
      marginBottom: "20px",
    },
    input: {
      borderRadius: "8px",
      padding: "12px",
      border: "1px solid #ced4da",
      fontSize: "16px",
    },
    button: {
      borderRadius: "8px",
      padding: "12px",
      fontSize: "16px",
      fontWeight: "bold",
    },
    title: {
      textAlign: "center",
      fontWeight: "700",
      marginBottom: "25px",
      color: "#333",
    },
  };

  return (
    <div style={styles.container}>
      <img
        loading="lazy"
        src="https://equitypandit.in/ep-imgs/ep-advisor-logo.svg"
        alt="EP-Investment-Advisor"
        style={styles.logo}
      />

      <div style={styles.card}>
        <h2 style={styles.title}>Admin Login</h2>

        {!otpSent ? (
          <form onSubmit={handleSendOtp}>
            <div className="mb-4">
              <label className="form-label fw-semibold">Phone Number</label>
              <input
                type="text"
                className="form-control"
                style={styles.input}
                value={phoneNumber}
                onChange={(e) => setPhoneNumber(e.target.value)}
                placeholder="Enter 10-digit phone number"
                required
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary w-100"
              style={styles.button}
              disabled={loading}
            >
              {loading ? "Sending..." : "Send OTP"}
            </button>
          </form>
        ) : (
          <form onSubmit={handleVerifyOtp}>
            <div className="mb-4">
              <label className="form-label fw-semibold">6-digit OTP</label>
              <input
                type="text"
                className="form-control"
                style={styles.input}
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                placeholder="Enter OTP"
                required
              />
            </div>
            <button
              type="submit"
              className="btn btn-primary w-100"
              style={styles.button}
              disabled={loading}
            >
              {loading ? "Verifying..." : "Verify OTP"}
            </button>
          </form>
        )}
      </div>

      <Toast />
    </div>
  );
}

export default AdminLogin;
